//! FastAPI framework recognizer.
//!
//! Detects FastAPI apps by import pattern and extracts routes from
//! decorator-based route declarations plus HTTP middleware.

use std::collections::HashMap;

use crate::cfg::ControlFlowGraph;
use crate::framework_recognizer::{
    FrameworkRecognizer, FrameworkTopology, HttpMethod, Middleware, Route,
};

pub struct FastAPIRecognizer;

impl FrameworkRecognizer for FastAPIRecognizer {
    fn framework_id(&self) -> &str {
        "fastapi"
    }

    fn language(&self) -> &str {
        "python"
    }

    fn detect(
        &self,
        source: &str,
        file_path: &str,
        cfgs: &[ControlFlowGraph],
    ) -> Option<FrameworkTopology> {
        let has_fastapi =
            source.contains("from fastapi import") || source.contains("import fastapi");

        if !has_fastapi {
            return None;
        }

        let mut routes = Vec::new();
        let mut middleware = Vec::new();
        let mut listen_port = None;
        let mut middleware_order = 0;
        let app_names = detect_app_names(source);
        let lines: Vec<&str> = source.lines().collect();

        for (i, line) in lines.iter().enumerate() {
            let trimmed = line.trim();

            for app_name in &app_names {
                if let Some(route_info) = parse_api_route_decorator(trimmed, app_name) {
                    if let Some(func_name) = find_decorated_function(&lines, i + 1) {
                        let handler_cfg_index =
                            cfgs.iter().position(|cfg| cfg.function_name == func_name);

                        for method in route_info.methods {
                            routes.push(Route {
                                method,
                                path: route_info.path.clone(),
                                handler_name: func_name.clone(),
                                handler_cfg_index,
                                source_start: 0,
                                source_end: 0,
                            });
                        }
                    }
                }

                for (decorator, method) in &[
                    ("get", HttpMethod::Get),
                    ("post", HttpMethod::Post),
                    ("put", HttpMethod::Put),
                    ("delete", HttpMethod::Delete),
                    ("patch", HttpMethod::Patch),
                    ("head", HttpMethod::Head),
                    ("options", HttpMethod::Options),
                ] {
                    let pattern = format!("@{}.{}(", app_name, decorator);
                    if trimmed.starts_with(&pattern) {
                        if let Some(path) = extract_string_arg(&trimmed[pattern.len()..]) {
                            if let Some(func_name) = find_decorated_function(&lines, i + 1) {
                                let handler_cfg_index =
                                    cfgs.iter().position(|cfg| cfg.function_name == func_name);

                                routes.push(Route {
                                    method: method.clone(),
                                    path,
                                    handler_name: func_name,
                                    handler_cfg_index,
                                    source_start: 0,
                                    source_end: 0,
                                });
                            }
                        }
                    }
                }

                let middleware_pattern = format!("@{}.middleware(", app_name);
                if trimmed.starts_with(&middleware_pattern) {
                    if let Some(func_name) = find_decorated_function(&lines, i + 1) {
                        middleware.push(Middleware {
                            name: func_name,
                            path_prefix: None,
                            handler_cfg_index: None,
                            order: middleware_order,
                        });
                        middleware_order += 1;
                    }
                }
            }

            if trimmed.contains("uvicorn.run(") {
                if let Some(port) = extract_port_kwarg(trimmed) {
                    listen_port = Some(port);
                }
            }
        }

        if routes.is_empty() {
            return None;
        }

        Some(FrameworkTopology {
            framework: "fastapi".to_string(),
            language: "python".to_string(),
            file_path: file_path.to_string(),
            routes,
            middleware,
            listen_port,
            config: HashMap::new(),
        })
    }
}

struct RouteDecoratorInfo {
    path: String,
    methods: Vec<HttpMethod>,
}

fn detect_app_names(source: &str) -> Vec<String> {
    let mut names = Vec::new();

    for line in source.lines() {
        let trimmed = line.trim();
        if trimmed.contains("= FastAPI(") {
            if let Some(name) = trimmed
                .split('=')
                .next()
                .map(|candidate| candidate.trim().to_string())
            {
                if !name.is_empty() {
                    names.push(name);
                }
            }
        }
    }

    if names.is_empty() {
        names.push("app".to_string());
    }

    names
}

fn parse_api_route_decorator(line: &str, app_name: &str) -> Option<RouteDecoratorInfo> {
    let prefix = format!("@{}.api_route(", app_name);
    if !line.starts_with(&prefix) {
        return None;
    }

    let rest = &line[prefix.len()..];
    let path = extract_string_arg(rest)?;
    let methods = if let Some(methods_pos) = rest.find("methods=") {
        parse_methods_list(&rest[methods_pos + 8..])
    } else {
        vec![HttpMethod::Get]
    };

    Some(RouteDecoratorInfo { path, methods })
}

fn parse_methods_list(s: &str) -> Vec<HttpMethod> {
    let mut methods = Vec::new();
    let s = s.trim();
    let mut in_quote = false;
    let mut quote_char = ' ';
    let mut current = String::new();

    for c in s.chars() {
        if !in_quote && (c == '\'' || c == '"') {
            in_quote = true;
            quote_char = c;
            current.clear();
        } else if in_quote && c == quote_char {
            in_quote = false;
            match current.to_uppercase().as_str() {
                "GET" => methods.push(HttpMethod::Get),
                "POST" => methods.push(HttpMethod::Post),
                "PUT" => methods.push(HttpMethod::Put),
                "DELETE" => methods.push(HttpMethod::Delete),
                "PATCH" => methods.push(HttpMethod::Patch),
                "HEAD" => methods.push(HttpMethod::Head),
                "OPTIONS" => methods.push(HttpMethod::Options),
                "ALL" => methods.push(HttpMethod::All),
                _ => {}
            }
        } else if in_quote {
            current.push(c);
        } else if c == ']' {
            break;
        }
    }

    if methods.is_empty() {
        vec![HttpMethod::Get]
    } else {
        methods
    }
}

fn find_decorated_function(lines: &[&str], start: usize) -> Option<String> {
    for line in lines.iter().skip(start) {
        let trimmed = line.trim();
        if trimmed.is_empty() || trimmed.starts_with('@') {
            continue;
        }
        if let Some(rest) = trimmed.strip_prefix("def ") {
            let name: String = rest
                .chars()
                .take_while(|c| c.is_alphanumeric() || *c == '_')
                .collect();
            if !name.is_empty() {
                return Some(name);
            }
        }
        if let Some(rest) = trimmed.strip_prefix("async def ") {
            let name: String = rest
                .chars()
                .take_while(|c| c.is_alphanumeric() || *c == '_')
                .collect();
            if !name.is_empty() {
                return Some(name);
            }
        }
        break;
    }
    None
}

fn extract_string_arg(s: &str) -> Option<String> {
    let s = s.trim();
    let quote = s.chars().next()?;
    if quote != '\'' && quote != '"' {
        return None;
    }
    let rest = &s[1..];
    let end = rest.find(quote)?;
    Some(rest[..end].to_string())
}

fn extract_port_kwarg(s: &str) -> Option<u16> {
    if let Some(port_pos) = s.find("port=") {
        let rest = &s[port_pos + 5..];
        let num_str: String = rest.chars().take_while(|c| c.is_ascii_digit()).collect();
        return num_str.parse().ok();
    }
    None
}
